// Normalise the IMAP payload into a stable shape for downstream nodes.
const j = $input.item.json;
const from = typeof j.from === 'object' ? (j.from.text || j.from.value?.[0]?.address || '') : (j.from || '');
const body = j.textPlain || j.text || (j.textHtml ? j.textHtml.replace(/<[^>]+>/g, ' ') : '') || '';
return { json: { subject: j.subject || '(no subject)', body: String(body).slice(0, 4000), from } };

