// Parse Groq's JSON reply and build the task payload.
let parsed = {};
try { parsed = JSON.parse($json.choices[0].message.content); } catch (e) { parsed = {}; }
const subject = $('Normalize Email').item.json.subject;
const priorities = ['low', 'medium', 'high'];
const payload = {
  title: (parsed.title && String(parsed.title).trim()) || subject,
  description: parsed.description ? String(parsed.description) : $('Normalize Email').item.json.body.slice(0, 500),
  priority: priorities.includes(parsed.priority) ? parsed.priority : 'medium',
  due_at: parsed.due_at || null,
  source: 'email'
};
return { json: payload };
